// Throttle 5 concurrent HTTP calls
private readonly SemaphoreSlim _throttle = new(5, 5);

public async Task<IReadOnlyList<Result>> ProcessAllAsync(
    IEnumerable<Item> items, CancellationToken ct)
{
    var tasks = items.Select(async item =>
    {
        await _throttle.WaitAsync(ct);
        try { return await ProcessItemAsync(item, ct); }
        finally { _throttle.Release(); } // PHẢI trong finally
    });
    return await Task.WhenAll(tasks);
}

// Mutex pattern (binary semaphore, 1 writer at a time)
private readonly SemaphoreSlim _writeLock = new(1, 1);

public async Task<T> GetOrCreateAsync<T>(
    string key, Func<Task<T>> factory, CancellationToken ct)
{
    if (_cache.TryGetValue(key, out T? cached)) return cached!;

    await _writeLock.WaitAsync(ct);
    try
    {
        // Double-check sau khi có lock
        if (_cache.TryGetValue(key, out cached)) return cached!;
        var value = await factory();
        _cache[key] = value;
        return value;
    }
    finally { _writeLock.Release(); }
}
